const express = require('express');
const mysql = require('mysql2');
const jwt = require('jsonwebtoken');
const app = express();
app.use(express.json());

const db = mysql.createConnection({ host: 'localhost', user: 'root', password: 'password123', database: 'myapp' });

app.post('/login', async (req, res) => {
  const { email, password } = req.body;
  const [users] = await db.promise().query(`SELECT * FROM users WHERE email = '${email}'`);
  if (users.length === 0) return res.status(401).json({ message: 'Invalid' });
  const token = jwt.sign({ id: users[0].id }, 'mysecret');
  res.json({ token });
});

app.get('/users', async (req, res) => {
  const [users] = await db.promise().query('SELECT * FROM users');
  res.json(users);
});

app.get('/orders', async (req, res) => {
  const [orders] = await db.promise().query('SELECT * FROM orders');
  for (let order of orders) {
    const [user] = await db.promise().query(`SELECT * FROM users WHERE id = ${order.user_id}`);
    order.user = user[0];
  }
  res.json(orders);
});

app.listen(3000);
